import{_ as d,o as e,c as a,a2 as o}from"./chunks/framework.CIFdlppq.js";const _=JSON.parse('{"title":"配置项说明","description":"","frontmatter":{},"headers":[],"relativePath":"reference/config.md","filePath":"reference/config.md","lastUpdated":1782678748000}'),n={name:"reference/config.md"};function s(c,t,r,h,l,i){return e(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h1><p>所有配置可通过环境变量或 <code>.env</code> 文件设置。</p><h2 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h2><p>环境变量 &gt; <code>.env</code> 文件 &gt; 默认值</p><h2 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>PORT</code></td><td><code>3456</code></td><td>HTTP 模式监听端口</td></tr><tr><td><code>NODE_ENV</code></td><td><code>production</code></td><td>运行环境（production/development/test）</td></tr></tbody></table><h2 id="产物配置" tabindex="-1">产物配置 <a class="header-anchor" href="#产物配置" aria-label="Permalink to &quot;产物配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>VALIDPILOT_ARTIFACTS_DIR</code></td><td><code>./artifacts</code></td><td>验证产物存放目录</td></tr><tr><td><code>VALIDPILOT_RETENTION_DAYS</code></td><td><code>7</code></td><td>产物保留天数</td></tr></tbody></table><h2 id="安全配置" tabindex="-1">安全配置 <a class="header-anchor" href="#安全配置" aria-label="Permalink to &quot;安全配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>VALIDPILOT_REDACTION</code></td><td><code>false</code></td><td>启用敏感信息脱敏</td></tr><tr><td><code>VALIDPILOT_ALLOWLIST</code></td><td><code>*</code></td><td>域名白名单，逗号分隔</td></tr><tr><td><code>VALIDPILOT_BLOCKED_HOSTS</code></td><td><code>&#39;&#39;</code></td><td>域名黑名单，逗号分隔</td></tr><tr><td><code>MCP_API_KEY</code></td><td><code>&#39;&#39;</code></td><td>HTTP 模式 API Key</td></tr></tbody></table><h2 id="ssh-远程隧道" tabindex="-1">SSH / 远程隧道 <a class="header-anchor" href="#ssh-远程隧道" aria-label="Permalink to &quot;SSH / 远程隧道&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>SSH_PASS</code></td><td><code>&#39;&#39;</code></td><td>SSH 密码</td></tr><tr><td><code>SSH_KEY_PATH</code></td><td><code>&#39;&#39;</code></td><td>SSH 私钥路径</td></tr><tr><td><code>SSH_USER</code></td><td><code>&#39;&#39;</code></td><td>SSH 用户名</td></tr><tr><td><code>SSH_HOST</code></td><td><code>&#39;&#39;</code></td><td>SSH 主机地址</td></tr></tbody></table><h2 id="浏览器配置" tabindex="-1">浏览器配置 <a class="header-anchor" href="#浏览器配置" aria-label="Permalink to &quot;浏览器配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>BROWSER_HEADLESS</code></td><td><code>true</code></td><td>无头模式</td></tr><tr><td><code>BROWSER_VIEWPORT_WIDTH</code></td><td><code>1280</code></td><td>视口宽度</td></tr><tr><td><code>BROWSER_VIEWPORT_HEIGHT</code></td><td><code>720</code></td><td>视口高度</td></tr><tr><td><code>BROWSER_TIMEOUT</code></td><td><code>30000</code></td><td>超时时间（毫秒）</td></tr></tbody></table><h2 id="ai-配置" tabindex="-1">AI 配置 <a class="header-anchor" href="#ai-配置" aria-label="Permalink to &quot;AI 配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>AI_PROVIDER</code></td><td><code>&#39;&#39;</code></td><td>AI 提供商（openai/deepseek/qwen）</td></tr><tr><td><code>AI_API_KEY</code></td><td><code>&#39;&#39;</code></td><td>AI API Key</td></tr><tr><td><code>AI_BASE_URL</code></td><td><code>&#39;&#39;</code></td><td>AI API 基础地址</td></tr><tr><td><code>AI_MODEL</code></td><td><code>&#39;&#39;</code></td><td>AI 模型名称</td></tr></tbody></table><h2 id="视觉对比配置" tabindex="-1">视觉对比配置 <a class="header-anchor" href="#视觉对比配置" aria-label="Permalink to &quot;视觉对比配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>VISUAL_THRESHOLD</code></td><td><code>0.1</code></td><td>默认差异阈值</td></tr><tr><td><code>VISUAL_BASELINE_DIR</code></td><td><code>artifacts/visual/baseline</code></td><td>基线图目录</td></tr></tbody></table><h2 id="env-文件示例" tabindex="-1">.env 文件示例 <a class="header-anchor" href="#env-文件示例" aria-label="Permalink to &quot;.env 文件示例&quot;">​</a></h2><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 基础</span></span>
<span class="line"><span>PORT=3456</span></span>
<span class="line"><span>NODE_ENV=development</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 产物</span></span>
<span class="line"><span>VALIDPILOT_ARTIFACTS_DIR=./artifacts</span></span>
<span class="line"><span>VALIDPILOT_RETENTION_DAYS=7</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 安全</span></span>
<span class="line"><span>VALIDPILOT_REDACTION=true</span></span>
<span class="line"><span>VALIDPILOT_ALLOWLIST=localhost,example.com</span></span>
<span class="line"><span>MCP_API_KEY=your-secret-key</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 浏览器</span></span>
<span class="line"><span>BROWSER_HEADLESS=true</span></span>
<span class="line"><span>BROWSER_VIEWPORT_WIDTH=1920</span></span>
<span class="line"><span>BROWSER_VIEWPORT_HEIGHT=1080</span></span></code></pre></div>`,20)])])}const b=d(n,[["render",s]]);export{_ as __pageData,b as default};
